class SideNavbarControls{constructor(){this.sideNav=document.getElementById("side-navigation"),document.getElementById("side-navigation-close-button").onclick=()=>{this.closeNav()},document.getElementById("side-navigation-open-button").onclick=()=>{this.openNav()}}openNav(){this.sideNav.style.width="250px"}closeNav(){this.sideNav.style.width="0"}}export{SideNavbarControls};